/**
 * Type-safe environment variable access
 * Generated by AIX Evolution Loop
 */

import { z } from 'zod';

const envSchema = z.object({
  // Pi Network
  PI_API_KEY:       z.string().min(1),
  PI_APP_ID:        z.string().min(1),
  PI_ENV:           z.enum(['sandbox', 'production']).default('sandbox'),

  // OpenAI
  OPENAI_API_KEY:   z.string().min(1),

  // Upstash Redis
  KV_REST_API_URL:  z.string().url(),
  KV_REST_API_TOKEN: z.string().min(1),

  // Auth
  JWT_SECRET:       z.string().min(32),

  // App
  NODE_ENV:         z.enum(['development', 'test', 'production']).default('development'),
  APP_URL:          z.string().url().default('http://localhost:3000'),
});

function requireEnv(key: string): string {
  const val = process.env[key];
  if (!val) {
    if (process.env.NODE_ENV === 'production') {
      throw new Error(`CRITICAL: Missing required environment variable: ${key}`);
    }
    console.warn(`⚠️  Missing environment variable: ${key}`);
    return '';
  }
  return val;
}

export const env = {
  // Pi Network
  PI_API_KEY:       requireEnv('PI_API_KEY'),
  PI_APP_ID:        requireEnv('PI_APP_ID'),
  PI_ENV:           (process.env.PI_ENVIRONMENT || 'sandbox') as 'sandbox' | 'production',

  // OpenAI
  OPENAI_API_KEY:   requireEnv('OPENAI_API_KEY'),

  // Upstash Redis
  KV_REST_API_URL:  requireEnv('KV_REST_API_URL'),
  KV_REST_API_TOKEN: requireEnv('KV_REST_API_TOKEN'),

  // Auth
  JWT_SECRET:       requireEnv('JWT_SECRET'),

  // App
  NODE_ENV:         process.env.NODE_ENV || 'development',
  APP_URL:          process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000',
} as const;

export type Env = typeof env;

/**
 * Validate all environment variables
 * Should be called at startup
 */
export function validateEnv() {
  try {
    envSchema.parse({
      ...env,
      // Handle the case where requireEnv returned empty string in dev
      JWT_SECRET: process.env.JWT_SECRET || 'placeholder_for_validation_only_32_chars_long',
    });
  } catch (error) {
    if (error instanceof z.ZodError) {
      console.error('❌ Invalid environment variables:', error.flatten().fieldErrors);
      if (process.env.NODE_ENV === 'production') {
        throw new Error('Environment validation failed');
      }
    }
  }
}

